            array = id.split('_'),
            pos = -1,
            len = array.length - 1,
            i = 1,
            key = array[0];

        for (i; i < len; i++) {
            key += '_' + array[i];
        }

        pos = Settings_value_keys.indexOf(key);

        if (pos > -1) {
            Settings_RemoveInputFocus();
            Settings_cursorY = pos;
            Settings_inputFocus(Settings_cursorY);
        }
