function UserLiveFeedobj_CurrentGameUpdateLastPositionGame() {
    UserLiveFeed_obj[UserLiveFeedobj_CurrentGamePos].LastPositionGame[Play_data.data[18]] = UserLiveFeed_FeedPosY[UserLiveFeedobj_CurrentGamePos];
}
